```javascript
/**
 * 创建一个防抖（debounce）函数
 * 
 * @param {Function} fn       - 需要防抖的目标函数
 * @param {number}   delay    - 延迟时间，单位毫秒
 * @param {Object}   options  - 可选配置
 * @param {boolean}  options.leading  - 是否在延迟开始前立即执行一次（默认 false）
 * @param {boolean}  options.trailing - 是否在延迟结束后执行最后一次（默认 true）
 * @returns {Function} 防抖处理后的函数（附带 cancel / flush 方法）
 */
function debounce(fn, delay = 300, options = {}) {
  const { leading = false, trailing = true } = options;

  let timer = null;          // setTimeout 的句柄
  let lastArgs = null;       // 最近一次调用的参数
  let lastThis = null;       // 最近一次调用的 this
  let result = undefined;    // fn 的返回值（仅 leading 调用时同步返回）

  let isInvoked = false;     // 标记 leading 是否已触发（用于 leading + trailing 逻辑）

  /**
   * 在延迟结束后执行 trailing 调用
   */
  const invokeTrailing = () => {
    if (!trailing) return;
    if (lastArgs) {
      result = fn.apply(lastThis, lastArgs);
      lastArgs = null;
      lastThis = null;
      isInvoked = false;
    }
    timer = null;
  };

  /**
   * 执行 leading 调用（如果有 pending 的 trailing 会取消）
   */
  const invokeLeading = () => {
    if (!leading) return;
    result = fn.apply(lastThis, lastArgs);
    lastArgs = null;
    lastThis = null;
    isInvoked = true;       // 标记本次 leading 已执行
  };

  /**
   * 清除定时器
   */
  const clearTimer = () => {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
  };

  /**
   * 返回的防抖函数
   */
  const debounced = function (...args) {
    lastArgs = args;
    lastThis = this;

    clearTimer();

    // leading 且尚未被调用过 → 立即执行
    if (leading && !isInvoked) {
      invokeLeading();
    }

    // 设置延迟，准备 trailing 执行
    if (trailing) {
      timer = setTimeout(invokeTrailing, delay);
    }
  };

  /**
   * 立即取消本次 pending 调用
   */
  debounced.cancel = () => {
    clearTimer();
    lastArgs = null;
    lastThis = null;
    isInvoked = false;
  };

  /**
   * 立即执行 pending 的 trailing 调用（如有）
   */
  debounced.flush = () => {
    clearTimer();
    if (lastArgs) {
      result = fn.apply(lastThis, lastArgs);
      lastArgs = null;
      lastThis = null;
      isInvoked = false;
    }
  };

  return debounced;
}

// ─── 使用示例 ─────────────────────────────────────────

// 1. 基本用法：搜索输入防抖
const searchInput = document.querySelector('#search');
const handleSearch = debounce((e) => {
  console.log('发起搜索请求:', e.target.value);
}, 500);
searchInput.addEventListener('input', handleSearch);

// 2. 立即执行（leading）：提交按钮防止双击
const handleSubmit = debounce(
  () => console.log('表单已提交'),
  1000,
  { leading: true, trailing: false }
);
submitBtn.addEventListener('click', handleSubmit);

// 3. 取消与立即执行
handleSubmit.cancel();   // 取消 pending 调用
handleSubmit.flush();    // 立即执行 pending 调用

// 4. Node.js / 一般函数防抖
const log = debounce((msg) => console.log(msg), 200);
log('A'); log('B'); log('C');  // 只输出一次 'C'（200ms 后）
```

### 关键要点

| 特性 | 说明 |
|------|------|
| **trailing**（默认） | 连续触发时，只在停止触发后 delay 毫秒执行一次 |
| **leading** | 在触发开始时就立即执行一次，之后在 delay 内不再重复执行 |
| **leading + trailing** | 开始立即执行一次，停止后 delay 毫秒再执行最后一次 |
| **flush()** | 立即执行所有 pending 调用，常用于组件卸载前 |
| **cancel()** | 取消 pending 调用，常用于组件卸载时的清理 |

### 与节流（throttle）的区别

```
Debounce:  ------[ 连续敲击键盘 ]-----↓
           等待停歇后执行              ✓ 只执行一次

Throttle:  ------[ 连续滚动页面 ]-----↓
           固定间隔执行                ✓ 每 200ms 执行一次
```

**一句话总结：** debounce 是「等待停下来才执行」，适合输入框搜索；throttle 是「固定频率执行」，适合滚动/拖拽事件。

